// Normaliza `urls` e cria 1 item por URL (string)
const extras = {
  telefone: $json.telefone ?? '',
  id_conversa: $json.id_conversa ?? '',
  id_mensagem: $json.id_mensagem ?? '',
  entrada: $json.entrada ?? ''
};

function toList(raw) {
  if (!raw) return [];
  if (Array.isArray(raw)) return raw;
  if (typeof raw === 'string') {
    const s = raw.trim();
    if (!s) return [];
    if (s.startsWith('[')) {
      try {
        const arr = JSON.parse(s);
        return Array.isArray(arr) ? arr : [];
      } catch { return []; }
    }
    if (s.includes(',')) return s.split(',').map(x => x.trim()).filter(Boolean);
    return [s];
  }
  return [];
}

const urls = toList($json.urls).filter(Boolean);

return urls.map(u => ({
  json: { ...extras, urls: u }
}));

/**
 * HTML Generator — Relatório de Exames (HTML5 + CSS responsivo)
 * Entradas possíveis (vindas do Agent/tools via $fromAI):
 *  - analysis (obj) | analyses (array)
 *  - raw | result | output | data | response  (string JSON OU objeto diretamente)
 * Saídas:
 *  - json.html, json.summary, json.analyses_received
 *  - binary.report (HTML em base64, se Buffer existir)
 */

const WARN_TOL = 0.05;           // 5%
const EMPTY_TEXT_POLICY = 'warn'; // 'warn' | 'crit'

/* ----------------- Utils básicos ----------------- */
function stripFences(s) {
  if (typeof s !== 'string') return s;
  let t = s.trim();
  // remove ```json ... ``` ou ``` ... ```
  t = t.replace(/^```[a-zA-Z]*\s*/i, '').replace(/```$/i, '').trim();
  return t;
}
function esc(s){ return String(s ?? '—').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function ptNumber(n){ if (typeof n !== 'number' || !isFinite(n)) return String(n ?? '—'); return n.toLocaleString('pt-BR',{ maximumFractionDigits: 2 }); }
function ptDate(d){
  if (!d) return '—';
  const dt = new Date(d);
  if (!isNaN(dt)) {
    const dd = String(dt.getDate()).padStart(2,'0');
    const mm = String(dt.getMonth()+1).padStart(2,'0');
    const yyyy = dt.getFullYear();
    return `${dd}/${mm}/${yyyy}`;
  }
  return String(d);
}

/* ----------------- Normalização de dados ----------------- */
function toISODate(s){
  if (!s || typeof s !== 'string') return null;
  const t = s.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  const m1 = /^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/.exec(t); // dd/mm/yyyy
  if (m1){
    const dd = m1[1].padStart(2,'0'), mm = m1[2].padStart(2,'0'), yyyy = m1[3];
    return `${yyyy}-${mm}-${dd}`;
  }
  return null;
}
function numOrNull(v){
  if (typeof v === 'number') return isFinite(v)? v : null;
  if (typeof v === 'string'){
    const t = v.replace(',', '.').trim();
    if (/^[\+\-]?\d+(\.\d+)?$/.test(t)) return Number(t);
  }
  return null;
}
function cleanResult(r){
  if (!r || typeof r !== 'object') return null;
  const out = { ...r };
  if ('value' in out){
    const n = numOrNull(out.value);
    if (n !== null) out.value = n;
  }
  if ('ref_min' in out){
    const n = numOrNull(out.ref_min);
    out.ref_min = (n !== null)? n : (typeof out.ref_min === 'number'? out.ref_min : null);
  }
  if ('ref_max' in out){
    const n = numOrNull(out.ref_max);
    out.ref_max = (n !== null)? n : (typeof out.ref_max === 'number'? out.ref_max : null);
  }
  if ('prev_value' in out){
    const n = numOrNull(out.prev_value);
    out.prev_value = (n !== null)? n : (typeof out.prev_value === 'number'? out.prev_value : null);
  }
  if (out.prev_date){
    out.prev_date = toISODate(String(out.prev_date)) ?? out.prev_date ?? null;
  }
  return out;
}
function normalizeOne(a){
  if (!a || typeof a !== 'object') return null;
  const out = { ...a };
  if (out.exam){
    if (out.exam.date_requested) out.exam.date_requested = toISODate(String(out.exam.date_requested)) ?? out.exam.date_requested ?? null;
    if (out.exam.date_report)    out.exam.date_report    = toISODate(String(out.exam.date_report))    ?? out.exam.date_report    ?? null;
  }
  if (Array.isArray(out.results)) out.results = out.results.map(cleanResult).filter(Boolean);
  if (!Array.isArray(out.notes)) out.notes = out.notes ? [String(out.notes)] : [];
  return out;
}

/* ----------------- Parse e elevação de root ----------------- */
function safeParseJsonish(maybeJson){
  // aceita string, objeto ou array
  if (!maybeJson) return null;
  if (typeof maybeJson === 'string'){
    const stripped = stripFences(maybeJson);
    try { return JSON.parse(stripped); } catch { return null; }
  }
  if (typeof maybeJson === 'object'){
    // já é objeto/array
    return maybeJson;
  }
  return null;
}

function looksLikeAnalysis(obj){
  return obj && typeof obj === 'object' && (
    obj.patient || obj.exam || obj.results || obj.notes || obj.metadata
  );
}
function coerceRoot(candidate){
  // candidate pode ser string JSON, obj com analysis/analyses, array de análises, ou analysis direto
  const data = safeParseJsonish(candidate) ?? candidate;

  if (!data) return null;

  if (Array.isArray(data)) {
    // array de análises?
    const arr = data.map(normalizeOne).filter(Boolean);
    return arr.length ? { analyses: arr } : null;
  }

  if (typeof data === 'object') {
    if (Array.isArray(data.analyses)) {
      const arr = data.analyses.map(normalizeOne).filter(Boolean);
      if (arr.length) return { analyses: arr };
    }
    if (data.analysis && typeof data.analysis === 'object') {
      const one = normalizeOne(data.analysis);
      if (one) return { analysis: one };
    }
    // objeto no formato da análise
    if (looksLikeAnalysis(data)) {
      const one = normalizeOne(data);
      if (one) return { analysis: one };
    }
    // tentar procurar de forma profunda
    for (const k of Object.keys(data)) {
      const v = data[k];
      const r = coerceRoot(v);
      if (r) return r;
    }
  }

  return null;
}

function getAnalysesFromInputs(){
  // 1) Vias "diretas" do Agent
  const one  = $fromAI('analysis', `{}`, 'json');
  const many = $fromAI('analyses', `[]`, 'json');

  if (many && Array.isArray(many) && many.length) {
    return { root: { analyses: many.map(normalizeOne).filter(Boolean) }, source: 'fromAI:analyses' };
  }
  if (one && Object.keys(one || {}).length){
    return { root: { analysis: normalizeOne(one) }, source: 'fromAI:analysis' };
  }

  // 2) Vias "genéricas" (string OU objeto)
  const candidates = [
    $fromAI('raw', ``, 'json') || $fromAI('raw', ``, 'string'),
    $fromAI('result', ``, 'json') || $fromAI('result', ``, 'string'),
    $fromAI('data', ``, 'json') || $fromAI('data', ``, 'string'),
    $fromAI('output', ``, 'json') || $fromAI('output', ``, 'string'),
    $fromAI('response', ``, 'json') || $fromAI('response', ``, 'string'),
  ].filter(v => v !== undefined && v !== null && String(v).trim() !== '');

  for (const c of candidates) {
    const r = coerceRoot(c);
    if (r) return { root: r, source: 'fromAI:generic' };
  }

  // 3) Nada encontrado
  return { root: null, source: 'none' };
}

/* ----------------- Lógica clínica (status/trend) ----------------- */
function computeStatus(r){
  const isNum = v => typeof v === 'number' && isFinite(v);
  const { value, ref_min, ref_max, ref_text } = r;
  if (isNum(value) && (isNum(ref_min) || isNum(ref_max))){
    const v = value;
    if (isNum(ref_min) && v < ref_min) return (v >= ref_min * (1 - WARN_TOL)) ? 'warn' : 'crit';
    if (isNum(ref_max) && v > ref_max) return (v <= ref_max * (1 + WARN_TOL)) ? 'warn' : 'crit';
    return 'ok';
  }
  if (ref_text != null){
    const a = String(value ?? '').trim().toLowerCase();
    const b = String(ref_text ?? '').trim().toLowerCase();
    if (!a && b) return EMPTY_TEXT_POLICY;
    if (!b) return 'ok';
    return (a === b) ? 'ok' : 'crit';
  }
  return 'ok';
}
function statusLabel(c){ return c==='ok'?'Normal':(c==='warn'?'Limítrofe':'Alterado'); }
function trendInfo(r){
  const isNum = v => typeof v === 'number' && isFinite(v);
  if (!isNum(r.value) || !isNum(r.prev_value)) return { text:'—' };
  const d = r.value - r.prev_value;
  const pct = r.prev_value === 0 ? null : (d / r.prev_value) * 100;
  const absTxt = `${d>=0?'+':''}${ptNumber(d)}`;
  const pctTxt = (pct==null)? '' : ` (${pct>=0?'+':''}${ptNumber(pct)}%)`;
  let arrow = '■ estável';
  if (pct != null){ if (pct > 1) arrow='▲ aumento'; else if (pct < -1) arrow='▼ queda'; }
  return { text: `${absTxt}${pctTxt} · ${arrow}` };
}
function mapSection(exam){
  const explicit = String(exam?.section ?? '').toLowerCase().trim();
  if (explicit) return explicit;
  const t = String(exam?.type ?? '').toLowerCase();
  if (/urina|eas|urin/.test(t)) return 'urina';
  if (/hemograma|hematologia|eritro|leuco|plaqueta/.test(t)) return 'hematologia';
  if (/bioqu[ií]mica|metabolismo|enzima|creatinina|ureia|glic/.test(t)) return 'bioquimica';
  if (/imagem|raio-x|radiografia|resson|tomografia|ultra/.test(t)) return 'imagem';
  return 'geral';
}

/* ----------------- Renderização ----------------- */
function renderSummaryCards(exam, counts){ return `
  <div class="grid cols-3">
    <div class="card">
      <div class="kv"><span class="k">Tipo de Exame</span><span class="v">${esc(exam.type)}</span></div>
      <div class="kv"><span class="k">Laboratório</span><span class="v">${esc(exam.lab)}</span></div>
    </div>
    <div class="card">
      <div class="kv"><span class="k">Data (Solicitação)</span><span class="v">${ptDate(exam.date_requested)}</span></div>
      <div class="kv"><span class="k">Data (Laudo)</span><span class="v">${ptDate(exam.date_report)}</span></div>
    </div>
    <div class="card">
      <div class="kv"><span class="k">Alterações</span><span class="v"><span class="badge crit" aria-label="Resultados alterados">${counts.crit}</span></span></div>
      <div class="kv"><span class="k">Limítrofes</span><span class="v"><span class="badge warn" aria-label="Resultados limítrofes">${counts.warn}</span></span></div>
    </div>
  </div>
`; }
function buildTableRows(results){
  return results.map(r=>{
    const unit = r.unit ? ` ${esc(r.unit)}` : '';
    const res = (typeof r.value === 'number') ? `${ptNumber(r.value)}${unit}` : esc(r.value ?? '—');
    let refCol = '—';
    if (typeof r.ref_min === 'number' || typeof r.ref_max === 'number'){
      const min = (typeof r.ref_min === 'number') ? ptNumber(r.ref_min) : '—';
      const max = (typeof r.ref_max === 'number') ? ptNumber(r.ref_max) : '—';
      refCol = `${min} – ${max}`;
    } else if (r.ref_text) {
      refCol = esc(r.ref_text);
    }
    const badgeClass = r._status === 'ok' ? 'ok' : (r._status === 'warn' ? 'warn' : 'crit');
    const badge = `<span class="badge ${badgeClass}" aria-label="Status: ${esc(r._status_label)}">${esc(r._status_label)}</span>`;
    return `
      <tr>
        <td data-label="Medida">${esc(r.name)}</td>
        <td data-label="Resultado">${res}</td>
        <td data-label="Ref.">${refCol}</td>
        <td data-label="Status">${badge}</td>
        <td data-label="Tendência" class="trend">${esc(r._trend)}</td>
      </tr>
    `;
  }).join('');
}
function renderExamSection(a){
  const patient = a.patient ?? {};
  const exam = a.exam ?? {};
  const results = Array.isArray(a.results) ? a.results : [];
  const notes = Array.isArray(a.notes) ? a.notes : [];

  const enriched = results.map(r=>{
    const cls = computeStatus(r);
    const label = statusLabel(cls);
    const tr = trendInfo(r);
    return { ...r, _status: cls, _status_label: label, _trend: tr.text };
  }).sort((x,y)=>{
    const rank = { crit:0, warn:1, ok:2 };
    const rx = rank[x._status] ?? 9;
    const ry = rank[y._status] ?? 9;
    if (rx !== ry) return rx - ry;
    return String(x.name ?? '').localeCompare(String(y.name ?? ''), 'pt-BR');
  });

  const counts = {
    crit: enriched.filter(r=>r._status==='crit').length,
    warn: enriched.filter(r=>r._status==='warn').length,
    ok:   enriched.filter(r=>r._status==='ok').length,
  };

  const summaryCards = renderSummaryCards(exam, counts);
  const alertBanner = (counts.crit>0 || counts.warn>0) ? `
    <div class="alert" role="status" aria-live="polite">
      <span class="icon">⚠️</span>
      <div><strong>Achados relevantes:</strong> ${counts.crit} alterado(s) e ${counts.warn} limítrofe(s). Revisão clínica recomendada.</div>
    </div>` : '';

  const rows = buildTableRows(enriched);
  const obsBlock = notes.length ? `
    <div class="card note" style="margin-top:14px">
      <strong>Observações:</strong>
      <ul style="margin:.4rem 0 0; padding-left:18px; color:var(--ink-3)">
        ${notes.map(n=>`<li>${esc(n)}</li>`).join('')}
      </ul>
    </div>` : '';

  return {
    sectionHtml: `
      <section>
        <h2 class="section-title">${esc(exam.type || 'Exame')}</h2>
        ${summaryCards}
        ${alertBanner}
        <div class="table-wrap" style="margin-top:14px">
          <table aria-label="Tabela de resultados">
            <thead>
              <tr>
                <th scope="col">Medida</th>
                <th scope="col">Resultado</th>
